const body = ($json.textPlain || "").toLowerCase();

let service = "ec2";
let region = "ap-south-1";
let operation = null;
let instanceId = null;

if (body.includes("list")) {
  operation = "list_instances";
} else if (body.includes("status")) {
  operation = "get_status";
} else if (body.includes("start")) {
  operation = "start";
} else if (body.includes("stop") || body.includes("shut")) {
  operation = "stop";
}

if (body.includes("mumbai") || body.includes("ap-south-1")) {
  region = "ap-south-1";
} else if (body.includes("us-east-1") || body.includes("virginia")) {
  region = "us-east-1";
}

const idMatch = body.match(/i-[a-z0-9]{8,17}/);
if (idMatch) {
  instanceId = idMatch[0];
}

return [{ json: { service, operation, region, instanceId } }];

const root = $json;

// helper to normalize array vs single object
function arr(x) {
  return Array.isArray(x) ? x : (x ? [x] : []);
}

const reservations = arr(root.DescribeInstancesResponse?.reservationSet?.item);
const out = [];

for (const r of reservations) {
  const instances = arr(r.instancesSet?.item);

  for (const i of instances) {
    const id = i.instanceId || "";
    const type = i.instanceType || "";
    const state = i.instanceState?.name || "";
    const az = i.placement?.availabilityZone || "";
    const dns = i.dnsName || "";
    const publicDns = i.publicIpDnsNameOptions?.publicIpv4DnsName || "";

    // tags handling
    const tags = arr(i.tagSet?.item);
    let name = "";
    for (const t of tags) {
      if (t.key === "Name") {
        name = t.value;
        break;
      }
    }

    out.push({ id, type, state, az, dns, publicDns, name });
  }
}

return out.length ? out : [{ note: "No instances found." }];

const items = [];

// Navigate safely into StartInstancesResponse
const resp = $json.StartInstancesResponse;
if (resp && resp.instancesSet && resp.instancesSet.item) {
  const raw = resp.instancesSet.item;
  const arr = Array.isArray(raw) ? raw : [raw];

  for (const i of arr) {
    items.push({
      id: i.instanceId || "",
      previous: i.previousState?.name || "",
      current: i.currentState?.name || "",
      operation: "start"
    });
  }
}

// If nothing found, still return a fallback
if (items.length === 0) {
  items.push({
    note: "No start information found in response",
    operation: "start"
  });
}

return items;

const items = [];

// Navigate safely into StopInstancesResponse
const resp = $json.StopInstancesResponse;
if (resp && resp.instancesSet && resp.instancesSet.item) {
  const raw = resp.instancesSet.item;
  const arr = Array.isArray(raw) ? raw : [raw];

  for (const i of arr) {
    items.push({
      id: i.instanceId || "",
      previous: i.previousState?.name || "",
      current: i.currentState?.name || "",
      operation: "stop"
    });
  }
}

// If nothing found, still return a failure note
if (items.length === 0) {
  items.push({
    note: "No stop information found in response",
    operation: "stop"
  });
}

return items;

const op = $json.operation || "list_instances";
const rows = $items().map(i => i.json);

let html = "";

if (op === 'list_instances' || op === 'get_status') {
  html += '<h2>EC2 Instance Details</h2>';
  html += '<table border="1" cellspacing="0" cellpadding="6" style="border-collapse:collapse;">';
  html += '<tr><th>ID</th><th>Type</th><th>State</th><th>Name</th><th>AZ</th><th>DNS</th><th>Public DNS</th></tr>';

  for (const r of rows) {
    if (r.id) {
      html += `<tr>
        <td>${r.id}</td>
        <td>${r.type}</td>
        <td>${r.state}</td>
        <td>${r.name || '-'}</td>
        <td>${r.az || '-'}</td>
        <td>${r.dns || '-'}</td>
        <td>${r.publicDns || '-'}</td>
      </tr>`;
    }
  }
  html += '</table>';
} 
else if (op === 'start' || op === 'stop') {
  html += `<h2>EC2 ${op.toUpperCase()} Results</h2>`;
  html += '<ul>';
  for (const r of rows) {
    let msg = "";
    if (op === 'start') {
      if (r.previous === "stopped" && (r.current === "pending" || r.current === "running")) {
        msg = `Instance ${r.id} is starting up `;
      } else if (r.previous === "running" && r.current === "running") {
        msg = `Instance ${r.id} is already running `;
      } else {
        msg = `Instance ${r.id} state: ${r.previous} → ${r.current}`;
      }
    }
    if (op === 'stop') {
      if (r.previous === "running" && (r.current === "stopping" || r.current === "stopped")) {
        msg = `Instance ${r.id} is shutting down `;
      } else if (r.previous === "stopped" && r.current === "stopped") {
        msg = `Instance ${r.id} is already stopped `;
      } else {
        msg = `Instance ${r.id} state: ${r.previous} → ${r.current}`;
      }
    }
    html += `<li>${msg}</li>`;
  }
  html += '</ul>';
} 
else {
  html = `<pre>${JSON.stringify(rows, null, 2)}</pre>`;
}

return {
  json: {
    subject: `EC2 ${op} Result`,
    body: html
  }
};

const items = [];
const resp = $json.RebootInstancesResponse || $json;
// Reboot response often doesn't return instancesSet; we confirm success via requestId
if (resp && resp.requestId) {
  items.push({ note: 'Reboot requested', operation: 'reboot', requestId: resp.requestId });
} else {
  items.push({ note: 'Reboot response not recognized', operation: 'reboot' });
}
return items;

const items = [];
const resp = $json.TerminateInstancesResponse;
if (resp && resp.instancesSet && resp.instancesSet.item) {
  const raw = resp.instancesSet.item;
  const arr = Array.isArray(raw) ? raw : [raw];
  for (const i of arr) {
    items.push({ id: i.instanceId || '', previous: i.previousState?.name || '', current: i.currentState?.name || '', operation: 'terminate' });
  }
} else if (resp && resp.terminatingInstances) {
  const raw = resp.terminatingInstances.item;
  const arr = Array.isArray(raw) ? raw : [raw];
  for (const i of arr) {
    items.push({ id: i.instanceId?.['#text'] || '', previous: i.previousState?.name?.['#text'] || '', current: i.currentState?.name?.['#text'] || '', operation: 'terminate' });
  }
} else if (resp && resp.requestId) {
  items.push({ note: 'Terminate requested', operation: 'terminate', requestId: resp.requestId });
} else {
  items.push({ note: 'No terminate info returned', operation: 'terminate' });
}
return items;

const resp = $json.CreateTagsResponse || $json;
if (resp && resp.requestId) {
  return [{ json: { note: `Tagged ${ Array.isArray($json.instanceId) ? $json.instanceId.join(',') : $json.instanceId } with ${$json.extra?.tagKey}=${$json.extra?.tagValue}`, operation: 'create_tag' } }];
}
return [{ json: { note: 'Tagging response not recognized', operation: 'create_tag' } }];

const resp = $json.DeleteTagsResponse || $json;
if (resp && resp.requestId) {
  return [{ json: { note: `Removed tag ${$json.extra?.tagKey} from ${ Array.isArray($json.instanceId) ? $json.instanceId.join(',') : $json.instanceId }`, operation: 'delete_tag' } }];
}
return [{ json: { note: 'Delete tag response not recognized', operation: 'delete_tag' } }];

const body = ($json.textPlain || "").toLowerCase();

let service = "ec2";
let region = "ap-south-1";
let operation = null;
let instanceId = null;
let extra = null;

// Basic intent detection (casual language)
if (body.includes("list") || body.includes("show me my instances") || body.includes("what instances")) {
  operation = "list_instances";
} else if (body.includes("status") || body.includes("what is the status") || body.includes("what's the status")) {
  operation = "get_status";
} else if (body.includes("start") || body.includes("boot")) {
  operation = "start";
} else if (body.includes("stop") || body.includes("shut") || body.includes("shutdown")) {
  operation = "stop";
} else if (body.includes("reboot") || body.includes("restart")) {
  operation = "reboot";
} else if (body.includes("terminate") || (body.includes("delete instance") && body.includes("confirm"))) {
  operation = "terminate";
} else if (body.includes("tag ") || body.includes("add tag") || body.includes("set tag")) {
  operation = "create_tag";
} else if (body.includes("remove tag") || body.includes("delete tag") || body.includes("untag")) {
  operation = "delete_tag";
} else if (body.includes("health") || body.includes("check health") || body.includes("describeinstancestatus")) {
  operation = "health_check";
} else if (body.includes("console") || body.includes("console output") || body.includes("getconsoleoutput")) {
  operation = "console_output";
} else if (body.includes("associate ip") || body.includes("associate address") || body.includes("assign elastic ip") ) {
  operation = "associate_address";
} else if (body.includes("disassociate ip") || body.includes("release address") ) {
  operation = "disassociate_address";
} else if (body.includes("create ami") || body.includes("create image") || body.includes("create_image") ) {
  operation = "create_image";
} else if (body.includes("snapshot") || body.includes("create snapshot")) {
  operation = "create_snapshot";
}

// region detection
if (body.includes("mumbai") || body.includes("ap-south-1")) {
  region = "ap-south-1";
} else if (body.includes("us-east") || body.includes("virginia") || body.includes("us-east-1")) {
  region = "us-east-1";
} else if (body.includes("eu-west-1") || body.includes("ireland")) {
  region = "eu-west-1";
}

// instance id detection (handles multiple ids comma separated)
const ids = body.match(/i-[a-z0-9]{8,17}/g);
if (ids && ids.length) {
  instanceId = ids.length === 1 ? ids[0] : ids; // can be array
}

// tag key/value detection (simple: key=value or key: value)
const tagMatch = body.match(/tag\s+(\w+)[=:]\s*([\w-]+)/i);
if (tagMatch) {
  extra = { tagKey: tagMatch[1], tagValue: tagMatch[2] };
}

// AMI name detection
const amiMatch = body.match(/ami name[=:]?\s*([\w- ]+)/i);
if (amiMatch) {
  extra = extra || {};
  extra.amiName = amiMatch[1].trim().replace(/\s+/g, '-');
}

// Elastic IP detection (simple IPv4 or allocation-id placeholder)
const ipMatch = body.match(/(\d{1,3}(?:\.\d{1,3}){3})/);
if (ipMatch) {
  extra = extra || {};
  extra.publicIp = ipMatch[1];
}

return [{ json: { service, operation, region, instanceId, extra } }];

const root = $json;

// helper to normalize array vs single object
function arr(x) {
  return Array.isArray(x) ? x : (x ? [x] : []);
}

const reservations = arr(root.DescribeInstancesResponse?.reservationSet?.item);
const out = [];

for (const r of reservations) {
  const instances = arr(r.instancesSet?.item);

  for (const i of instances) {
    const id = i.instanceId || "";
    const type = i.instanceType || "";
    const state = i.instanceState?.name || "";
    const az = i.placement?.availabilityZone || "";
    const dns = i.dnsName || "";
    const publicDns = i.publicIpDnsNameOptions?.publicIpv4DnsName || "";

    // tags handling
    const tags = arr(i.tagSet?.item);
    let name = "";
    for (const t of tags) {
      if (t.key === "Name") {
        name = t.value;
        break;
      }
    }

    out.push({ id, type, state, az, dns, publicDns, name, operation: $json.operation || 'list_instances' });
  }
}

return out.length ? out : [{ note: "No instances found.", operation: $json.operation || 'list_instances' }];

const items = [];

// Navigate safely into StartInstancesResponse
const resp = $json.StartInstancesResponse;
if (resp && resp.instancesSet && resp.instancesSet.item) {
  const raw = resp.instancesSet.item;
  const arr = Array.isArray(raw) ? raw : [raw];

  for (const i of arr) {
    items.push({
      id: i.instanceId || "",
      previous: i.previousState?.name || "",
      current: i.currentState?.name || "",
      operation: "start"
    });
  }
}

// If nothing found, still return a fallback
if (items.length === 0) {
  items.push({
    note: "No start information found in response",
    operation: "start"
  });
}

return items;

const items = [];

// Navigate safely into StopInstancesResponse
const resp = $json.StopInstancesResponse;
if (resp && resp.instancesSet && resp.instancesSet.item) {
  const raw = resp.instancesSet.item;
  const arr = Array.isArray(raw) ? raw : [raw];

  for (const i of arr) {
    items.push({
      id: i.instanceId || "",
      previous: i.previousState?.name || "",
      current: i.currentState?.name || "",
      operation: "stop"
    });
  }
}

// If nothing found, still return a failure note
if (items.length === 0) {
  items.push({
    note: "No stop information found in response",
    operation: "stop"
  });
}

return items;

const op = $json.operation || ($items(0)[0] && $items(0)[0].json.operation) || 'list_instances';
const rows = $items().map(i => i.json);

let html = '';

if (op === 'list_instances' || op === 'get_status') {
  html += '<h2>EC2 Instance Details</h2>';
  html += '<table border="1" cellspacing="0" cellpadding="6" style="border-collapse:collapse;">';
  html += '<tr><th>ID</th><th>Type</th><th>State</th><th>Name</th><th>AZ</th><th>DNS</th><th>Public DNS</th></tr>';
  for (const r of rows) {
    if (r.id) {
      html += `<tr>\n        <td>${r.id}</td>\n        <td>${r.type}</td>\n        <td>${r.state}</td>\n        <td>${r.name || '-'}</td>\n        <td>${r.az || '-'}</td>\n        <td>${r.dns || '-'}</td>\n        <td>${r.publicDns || '-'}</td>\n      </tr>`;
    }
  }
  html += '</table>';
} else if (op === 'start' || op === 'stop' || op === 'reboot' || op === 'terminate') {
  // casual human-friendly lines (no emoji)
  html += `<h2>EC2 ${op.toUpperCase()} Results</h2>`;
  html += '<ul>';
  for (const r of rows) {
    let msg = '';
    if (op === 'start') {
      if (r.previous === 'stopped' && (r.current === 'pending' || r.current === 'running')) {
        msg = `I started instance ${r.id}. It was stopped and is now booting up.`;
      } else if (r.previous === 'running' && r.current === 'running') {
        msg = `Instance ${r.id} is already running.`;
      } else {
        msg = `Instance ${r.id} status changed: ${r.previous} → ${r.current}.`;
      }
    }
    if (op === 'stop') {
      if (r.previous === 'running' && (r.current === 'stopping' || r.current === 'stopped')) {
        msg = `I stopped instance ${r.id}. It was running and is now shutting down.`;
      } else if (r.previous === 'stopped' && r.current === 'stopped') {
        msg = `Instance ${r.id} is already stopped.`;
      } else {
        msg = `Instance ${r.id} status changed: ${r.previous} → ${r.current}.`;
      }
    }
    if (op === 'reboot') {
      if (r.note) msg = `Reboot requested for ${r.requestId || r.id}.`; else msg = `Reboot requested for instance ${r.id}.`;
    }
    if (op === 'terminate') {
      if (r.current === 'shutting-down' || r.current === 'terminated' || r.note === 'Terminate requested') {
        msg = `Instance ${r.id} has been terminated or termination requested.`;
      } else {
        msg = `Instance ${r.id} termination result: ${r.previous} → ${r.current}.`;
      }
    }
    html += `<li>${msg}</li>`;
  }
  html += '</ul>';
}
else if (op === 'create_tag' || op === 'delete_tag') {
  html += '<h2>Tag Update</h2>';
  for (const r of rows) {
    html += `<p>${r.note}</p>`;
  }
}
else if (op === 'health_check') {
  html += '<h2>Instance Health Check</h2>';
  html += '<table border="1" cellspacing="0" cellpadding="6" style="border-collapse:collapse;">';
  html += '<tr><th>Instance ID</th><th>System Status</th><th>Instance Status</th></tr>';
  for (const r of rows) {
    if (r.instanceId) html += `<tr><td>${r.instanceId}</td><td>${r.systemStatus}</td><td>${r.instanceStatus}</td></tr>`;
  }
  html += '</table>';
}
else if (op === 'console_output') {
  html += '<h2>Console Output</h2>';
  for (const r of rows) {
    if (r.output) {
      // Console output may be base64; present as-is
      html += `<h3>${r.instanceId || ''}</h3><pre style="white-space:pre-wrap;">${r.output}</pre>`;
    } else {
      html += `<p>${r.note || 'No console output available.'}</p>`;
    }
  }
}
else if (op === 'associate_address') {
  for (const r of rows) {
    html += `<p>${r.note}</p>`;
  }
}
else if (op === 'create_image' || op === 'create_snapshot') {
  for (const r of rows) html += `<p>${r.note || (r.imageId ? 'Created AMI ' + r.imageId : '')}</p>`;
}
else {
  html = `<pre>${JSON.stringify(rows, null, 2)}</pre>`;
}

return {
  json: {
    subject: `EC2 ${op} Result`,
    body: html
  }
};
